// Generate human-readable HTML companions for the canonical Markdown docs.
//
// Convention (see docs/DECISIONS.md): every key `.md` is the AI-optimized source
// of truth and gets a committed `.html` sibling for humans. This script renders
// each doc to an `.html` file *next to* its `.md`, plus a browsable `index.html`
// at the repo root that links them all. The HTML is committed — it is the human
// view of the docs and is regenerated by `npm run build` (do not hand-edit).
import { existsSync, readFileSync, writeFileSync } from "node:fs";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";

import { mdToHtml } from "./md.mjs";

const HERE = dirname(fileURLToPath(import.meta.url));
const REPO = resolve(HERE, "..", "..", "..");

// Canonical docs that get an `.html` companion. `src` is repo-relative; the
// companion is written beside it (`X.md` -> `X.html`). `group` drives the
// index.html sections. Order within a group is preserved.
const DOCS = [
  { src: "README.md", title: "Overview", group: "Start here" },
  { src: "docs/README.md", title: "Documentation index", group: "Start here" },
  { src: "docs/ARCHITECTURE.md", title: "Architecture", group: "Reference" },
  { src: "docs/ROADMAP.md", title: "Roadmap & status", group: "Reference" },
  { src: "docs/CLI-SPEC.md", title: "CLI specification", group: "Reference" },
  { src: "docs/PACKAGES.md", title: "Package contracts", group: "Reference" },
  { src: "docs/DECISIONS.md", title: "Decisions (tiebreaker)", group: "Reference" },
  { src: "docs/PUBLISHING.md", title: "Publishing", group: "Reference" },
  { src: "apps/cli/README.md", title: "create-softeneers-app (CLI)", group: "Reference" },
  { src: "packages/config/README.md", title: "@softeneers/config", group: "Packages" },
  { src: "packages/env/README.md", title: "@softeneers/env", group: "Packages" },
  { src: "packages/db/README.md", title: "@softeneers/db", group: "Packages" },
  { src: "packages/auth/README.md", title: "@softeneers/auth", group: "Packages" },
  { src: "packages/email/README.md", title: "@softeneers/email", group: "Packages" },
  { src: "packages/storage/README.md", title: "@softeneers/storage", group: "Packages" },
  { src: "CONTRIBUTING.md", title: "Contributing", group: "Project" },
  { src: "TODO.md", title: "Original plan & intent", group: "Project" },
  { src: "PROJECT-BENCHMARK.md", title: "Maturity benchmark", group: "Project" },
  { src: "CLAUDE.md", title: "Agent contract (Claude Code)", group: "For AI agents" },
  { src: "AGENTS.md", title: "Agent contract (cross-tool)", group: "For AI agents" },
];

const STYLES = `
:root { color-scheme: light dark; }
* { box-sizing: border-box; }
body { font: 16px/1.6 -apple-system, system-ui, sans-serif; max-width: 820px;
  margin: 0 auto; padding: 2rem 1.25rem 4rem; color: #1a1a1a; background: #fff; }
@media (prefers-color-scheme: dark) { body { color: #e6e6e6; background: #141414; } }
.bar { display: flex; flex-wrap: wrap; gap: .9rem; align-items: baseline;
  padding-bottom: 1rem; margin-bottom: 1.5rem; border-bottom: 1px solid #8884; font-size: .9rem; }
.bar .spacer { flex: 1; }
.bar a { text-decoration: none; }
.src { color: #8889; font-family: ui-monospace, SFMono-Regular, Menlo, monospace; font-size: .85rem; }
h1, h2, h3 { line-height: 1.25; }
h2 { margin-top: 2rem; border-bottom: 1px solid #8883; padding-bottom: .3rem; }
a { color: #2563eb; } @media (prefers-color-scheme: dark) { a { color: #6ea8fe; } }
code { background: #8882; padding: .1em .35em; border-radius: 4px; font-size: .9em; }
pre { background: #8881; padding: 1rem; border-radius: 8px; overflow-x: auto; }
pre code { background: none; padding: 0; }
table { border-collapse: collapse; width: 100%; margin: 1rem 0; font-size: .92rem; }
th, td { border: 1px solid #8884; padding: .4rem .6rem; text-align: left; }
blockquote { border-left: 3px solid #8886; margin: 1rem 0; padding: .2rem 1rem; color: #8889; }
footer { margin-top: 3rem; padding-top: 1rem; border-top: 1px solid #8884; font-size: .85rem; color: #8889; }
.groups { display: grid; gap: 1.5rem; }
.group h2 { margin-top: 1.5rem; }
.group ul { list-style: none; padding: 0; margin: .5rem 0; }
.group li { margin: .35rem 0; }
.group .meta { color: #8889; font-size: .85rem; }
`;

// Depth of a repo-relative path => relative prefix back to the repo root.
function rootPrefix(src) {
  const depth = src.split("/").length - 1;
  return depth ? "../".repeat(depth) : "./";
}

function shell(title, headHtml, bodyHtml) {
  return `<!doctype html>
<html lang="en"><head><meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>${title} — Softeneers Framework</title>
<style>${STYLES}</style></head>
<body>
${headHtml}
<main>${bodyHtml}</main>
<footer>Softeneers Framework — human view generated from the canonical Markdown.
Do not edit by hand; run <code>npm run build</code> (the <code>.md</code> is the source of truth).</footer>
</body></html>`;
}

function docPage(doc) {
  const prefix = rootPrefix(doc.src);
  const mdName = doc.src.split("/").pop();
  const bar =
    `<div class="bar">` +
    `<a href="${prefix}index.html">← All docs</a>` +
    `<span class="spacer"></span>` +
    `<a class="src" href="./${mdName}">view ${mdName} source</a>` +
    `</div>`;
  return shell(doc.title, bar, mdToHtml(readFileSync(resolve(REPO, doc.src), "utf8")));
}

function indexPage(built) {
  const groups = [];
  for (const doc of built) {
    let g = groups.find((x) => x.name === doc.group);
    if (!g) groups.push((g = { name: doc.group, items: [] }));
    g.items.push(doc);
  }
  const sections = groups
    .map(
      (g) =>
        `<section class="group"><h2>${g.name}</h2><ul>` +
        g.items
          .map(
            (d) =>
              `<li><a href="${d.html}">${d.title}</a> ` +
              `<span class="meta">— <a class="src" href="${d.src}">${d.src}</a></span></li>`,
          )
          .join("") +
        `</ul></section>`,
    )
    .join("");
  const intro = `<h1>Softeneers Framework — Documentation</h1>
<p>Human-readable view of the canonical docs. Each page is generated from a
<code>.md</code> source of truth (linked beside it). The deployed marketing site
lives at <a href="https://softeneers-landing.vercel.app">softeneers-landing.vercel.app</a>.</p>`;
  return shell("Documentation", `<div class="bar"><strong>Softeneers Framework docs</strong></div>`, intro + `<div class="groups">${sections}</div>`);
}

let built = [];
let skipped = [];
for (const doc of DOCS) {
  const abs = resolve(REPO, doc.src);
  if (!existsSync(abs)) {
    skipped.push(doc.src);
    continue;
  }
  const htmlRel = doc.src.replace(/\.md$/, ".html");
  writeFileSync(resolve(REPO, htmlRel), docPage(doc));
  built.push({ ...doc, html: htmlRel });
}

writeFileSync(resolve(REPO, "index.html"), indexPage(built));

console.log(`docs-site: wrote ${built.length} companion page(s) + index.html`);
if (skipped.length) console.warn(`docs-site: skipped missing ${skipped.join(", ")}`);
